sp_angular_provider.script:
/* Use this Directive to add icons for the suspense date and have a table cell with a hover popover function
Note: AngularJS normalizes case-sensitive camelCase to case-insensitive kebab-case for the DOM.
Usage in a widget's HTML:
	<dtech-operational 
		dtech-task-title = "getTitle(item);"
		dtech-operational-object = "data.loadedOperationalOjbects[item.sys_id]"
			NOTE: These properties are on the operational Object
			number, , taskernumber, classification, tasker_type, short_description, 
			u_objective, instructions, priority, state, urgency
			status, category, sub_category, risk_flag, risk_impact_description,
			risk_impact_factor, risk_mitigation_strategy, risk_probability, risk_probability_description, risk_reason
			tasker_app_version
		dtech-is-modal="data.isModal"
        dtech-show-long-dates="{{data.showLongDates}}"
        table="{{data.table}}"
        task-sys-id="{{item.sys_id}}">
	</dtech-operational>


	The HTML for the directive is in	
	templateUrl: getTemplateUrl('x_153465_discovert_dtechOperational.html')
//
// Copyrights belong to Discover Technologies LLC. © 2023 Discover Technologies LLC
// Script Continued Below
// 2.8.5 | 2023-05-11 | mmcc | STRY0141856 - Stretch- PLACEHOLDER- Office Control
//   Updated to move variables into the Operational object to streamline the services and 
//   This had the added benefit of allowing the same service to be called from server and client.
//   Updated to change div to span on the main control so it would work in Tab Form with Tabs as well as the data table
// 2.8.1 | 2023-04-07 | raj | STRY0137371 - Icons to Represent Status
//  Created Directive
// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open
//  Added CONST_POPOVER_DELAY, d._isClosing, d.initTooltip, d.popoverDelay;
//  In function _init(element) added setting d.popoverDelay = CONST_POPOVER_DELAY;
//  Added function _initTooltip(); in function _leaveTooltip() set d._isClosing = true;
//   Added function _popoverDelay(); in function _showOperational(event) set d._isClosing = false;
//
*/
function dtechOperational(getTemplateUrl, spModal, $timeout, $window) {
	var CONST_TEMP_WAIT_OPERATIONAL = 600;

	// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; TODO: get from a service
	var CONST_POPOVER_DELAY = 1200;

	var dtOperational = {
		restrict: 'E',
		replace: true,
		// @: string 1 way, =: object 2 way, <: object 1 way
		scope: {
			dtechTaskTitle: "<?",
			dtechOperationalObject: "=",
			dtechField: "<",
			dtechShowLabel: "<?",
			dtechIsModal: "=",
			table: '@',
			taskSysId: '@'
		},
		controller: operationalCtrl,
		link: link,
		controllerAs: 'd',
		templateUrl: getTemplateUrl('x_153465_discovert_dtechOperational.html')
	};
	return dtOperational;

	function operationalCtrl($scope, $attrs, $animate, dtechTaskService) {
		var d = this;	
		d._isOverTooltip = false;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added, init to false
		d._isClosing = false;

		d.dtechOperationalToolTipOpen = _dtechOperationalToolTipOpen;
		d.dtechTaskTitle = _dtechTaskTitle;
		d.dtechField = _dtechField;
		d.dtechShowLabel = _dtechShowLabel;		

		// passed in data section
		d.dtechIsModal = _dtechIsModal;

		// directive's functional section
		d.enterTooltip = _enterTooltip;
		d.init = _init;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added
		d.initTooltip = _initTooltip;

		d.leaveTooltip = _leaveTooltip;
		d.openModal = _openModal;
		d.parentMouseLeave = _parentMouseLeave;

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added to set popover-popup-delay in the HTML
		d.popoverDelay = _popoverDelay;

		d.showOperational = _showOperational;

		function _dtechField(value){
			return $scope.dtechField;
		}

		function _dtechShowLabel(value){
			return $scope.dtechShowLabel;
		}

		function _dtechTaskTitle(value){
			return $scope.dtechTaskTitle;
		}

		function _dtechIsModal() {
			return $scope.dtechIsModal;
		}

		function _dtechOperationalToolTipOpen(){
			return $scope.dtechOperationalToolTipOpen;
		}

		// when the user hovers over the tooltip set overtooltip flag
		function _enterTooltip() {
			d._isOverTooltip = true;
		}

		// init()
		// initialize the control, called from the Link function
		// gets a reference to the element
		function _init(element) {

			d.$element = element;

			$scope.dtechOperationalToolTipOpen = 
				angular.isDefined($attrs.enterTooltip) ?
				$scope.$parent.$eval($attrs.dtechOperationalToolTipOpen) : false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set to const
			d.popoverDelay = CONST_POPOVER_DELAY;
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _initTooltip() {
			// if the user moved off of the parent before the tooltip opened, cancel the open
			if (d._isClosing == true) {
				_leaveTooltip();
				// d._isClosing = false;
			}
		}

		function _leaveTooltip() {
			d._isOverTooltip = false;
			$scope.dtechOperationalToolTipOpen = false;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set true
			d._isClosing = true;
		}

		// openModal()
		// this function is called from Template html
		// it is called when a user clicks on the open link
		function _openModal(event) {
			x_153465_discovert.twJS.openOperationalModal(spModal, $scope.dtechOperationalObject.operationalTitle, $scope.table, $scope.taskSysId);
			event.stopPropagation();
		}

		// _parentMouseLeave
		// this is the get function for the direcitve property parentMouseLeave
		// this function is called when the user hovers off the profile image
		function _parentMouseLeave() {
			$timeout(function() {
				if(!d._isOverTooltip){
					d.leaveTooltip();
				}
			}, CONST_TEMP_WAIT_OPERATIONAL);
		}

		// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; added function
		function _popoverDelay() {
			return d.popoverDelay;
		}

		function _showOperational(event) {
			$scope.dtechOperationalToolTipOpen = true;

			// 2.8.1 | 2023-05-11 | mmcc | STRY0139742 - Increase delaying when hover directives open; set false
			d._isClosing = false;

			var OperationalObject = $scope.dtechOperationalObject;
			if(!OperationalObject){
				OperationalObject = {};
				OperationalObject.taskId = $scope.taskSysId;
				OperationalObject.loaded = false;
			}
			if(!OperationalObject.loaded){
				d.isSpinnerShown = true;
				dtechTaskService.getOperationalInformation($scope.taskSysId).then(
					function(response){
						$scope.dtechOperationalObject = response.operationalInformation;
						d.isSpinnerShown = false;
						$scope.dtechOperationalObject.loaded = true;
					});
			}
			$scope.dtechOperationalObject=OperationalObject;
			$scope.dtechOperationalToolTipOpen = true;
		}		
	} // end function operationalCtrl

	// Link function links local methods to parent controller methods
	// see the list of events being monitored
	function link(scope, element, attrs, operationalCtrl) {
		// initialize the control
		operationalCtrl.init(element);
		scope.$on('$destroy',_destroy);
		// get the location of the element hovering over

		function _destroy() {
			element.remove();
		}
	}

}
